## Wait/Backoff Goroutine Analysis

| Function | Before | After | Change |
|----------|--------|-------|--------|
EOF
        
        # Extract wait-related goroutines (use cumulative column - $4)
        local wait_funcs=(
            "k8s.io/apimachinery/pkg/util/wait.BackoffUntil"
            "k8s.io/apimachinery/pkg/util/wait.BackoffUntilWithContext"
            "k8s.io/apimachinery/pkg/util/wait.JitterUntil"
            "k8s.io/apimachinery/pkg/util/wait.Until"
            "k8s.io/apimachinery/pkg/util/wait.(*Group).Start.func1"
            "sync.(*Cond).Wait"
            "github.com/rancher/lasso/pkg/controller.(*controller).runWorker"
            "github.com/rancher/lasso/pkg/controller.(*controller).processNextWorkItem"
        )
        
        local before_full
        before_full=$($PPROF -top "$before_goroutine" 2>/dev/null | head -100 || true)
        local after_full
        after_full=$($PPROF -top "$after_goroutine" 2>/dev/null | head -100 || true)
        
        for func in "${wait_funcs[@]}"; do
            # Create short display name
            local short_func
            short_func=$(echo "$func" | sed 's|k8s.io/apimachinery/pkg/util/||' | sed 's|github.com/rancher/||')
            # Extract cumulative count (column 4) - goroutines show 0 in flat but have cum values
            local before_count
            before_count=$(echo "$before_full" | grep -F "$func" | awk '{print $4}' | head -1 || true)
            local after_count
            after_count=$(echo "$after_full" | grep -F "$func" | awk '{print $4}' | head -1 || true)
            before_count=${before_count:-0}
            after_count=${after_count:-0}
            # Handle case where count might have % sign
            before_count=${before_count%\%}
            after_count=${after_count%\%}
            # Ensure numeric
            [[ "$before_count" =~ ^-?[0-9]+$ ]] || before_count=0
            [[ "$after_count" =~ ^-?[0-9]+$ ]] || after_count=0
            local change=$((after_count - before_count))
            echo "| \`$short_func\` | $before_count | $after_count | $change |"
        done
        
        echo ""
    fi

    cat << EOF
---
EOF
}

# Main
main() {
    if [[ $# -lt 2 ]]; then
        usage
    fi

    local before_input="$1"
    local after_input="$2"
    OUTPUT_FILE="${3:-}"

    # Validate inputs exist
    if [[ ! -e "$before_input" ]]; then
        log_error "Before input does not exist: $before_input"
        exit 1
    fi

    if [[ ! -e "$after_input" ]]; then
        log_error "After input does not exist: $after_input"
        exit 1
    fi

    check_requirements

    # Determine mode: tar files or plain directories
    local use_tar=false
    if is_tar_file "$before_input" || is_tar_file "$after_input"; then
        use_tar=true
    fi

    log_info "Comparing profiles: $before_input vs $after_input"

    if [[ "$use_tar" == "true" ]]; then
        if [[ -n "$OUTPUT_FILE" ]]; then
            generate_tar_report "$before_input" "$after_input" > "$OUTPUT_FILE"
            log_info "Report written to: $OUTPUT_FILE"
        else
            generate_tar_report "$before_input" "$after_input"
        fi
    else
        # Original directory-based comparison (backward compatible)
        if [[ ! -d "$before_input" ]]; then
            log_error "Before input is not a directory or tar file: $before_input"
            exit 1
        fi
        if [[ ! -d "$after_input" ]]; then
            log_error "After input is not a directory or tar file: $after_input"
            exit 1
        fi
        if [[ -n "$OUTPUT_FILE" ]]; then
            generate_report "$before_input" "$after_input" > "$OUTPUT_FILE"
            log_info "Report written to: $OUTPUT_FILE"
        else
            generate_report "$before_input" "$after_input"
        fi
    fi
}

main "$@"
